-- NPC and Monster template data migrated from MSSQL K_NPC and K_MONSTER tables
-- K_NPC: 1866 rows, K_MONSTER: 2156 rows

CREATE TABLE IF NOT EXISTS npc_template (
    s_sid SMALLINT NOT NULL,
    is_monster BOOLEAN NOT NULL DEFAULT FALSE,
    str_name VARCHAR(150),
    s_pid SMALLINT NOT NULL DEFAULT 0,
    s_size SMALLINT NOT NULL DEFAULT 100,
    i_weapon_1 INTEGER NOT NULL DEFAULT 0,
    i_weapon_2 INTEGER NOT NULL DEFAULT 0,
    by_group SMALLINT NOT NULL DEFAULT 0,
    by_act_type SMALLINT NOT NULL DEFAULT 0,
    by_type SMALLINT NOT NULL DEFAULT 0,
    by_family SMALLINT NOT NULL DEFAULT 0,
    by_rank SMALLINT NOT NULL DEFAULT 0,
    by_title SMALLINT NOT NULL DEFAULT 0,
    i_selling_group INTEGER NOT NULL DEFAULT 0,
    s_level SMALLINT NOT NULL DEFAULT 0,
    i_exp INTEGER NOT NULL DEFAULT 0,
    i_loyalty INTEGER NOT NULL DEFAULT 0,
    i_hp_point INTEGER NOT NULL DEFAULT 0,
    s_mp_point SMALLINT NOT NULL DEFAULT 0,
    s_atk SMALLINT NOT NULL DEFAULT 0,
    s_ac SMALLINT NOT NULL DEFAULT 0,
    s_hit_rate SMALLINT NOT NULL DEFAULT 0,
    s_evade_rate SMALLINT NOT NULL DEFAULT 0,
    s_damage SMALLINT NOT NULL DEFAULT 0,
    s_attack_delay SMALLINT NOT NULL DEFAULT 0,
    by_speed_1 SMALLINT NOT NULL DEFAULT 0,
    by_speed_2 SMALLINT NOT NULL DEFAULT 0,
    s_standtime SMALLINT NOT NULL DEFAULT 0,
    s_item SMALLINT NOT NULL DEFAULT 0,
    i_magic_1 INTEGER NOT NULL DEFAULT 0,
    i_magic_2 INTEGER NOT NULL DEFAULT 0,
    i_magic_3 INTEGER NOT NULL DEFAULT 0,
    s_fire_r SMALLINT NOT NULL DEFAULT 0,
    s_cold_r SMALLINT NOT NULL DEFAULT 0,
    s_lightning_r SMALLINT NOT NULL DEFAULT 0,
    s_magic_r SMALLINT NOT NULL DEFAULT 0,
    s_disease_r SMALLINT NOT NULL DEFAULT 0,
    s_poison_r SMALLINT NOT NULL DEFAULT 0,
    s_bulk SMALLINT NOT NULL DEFAULT 0,
    by_attack_range SMALLINT NOT NULL DEFAULT 0,
    by_search_range SMALLINT NOT NULL DEFAULT 0,
    by_tracing_range SMALLINT NOT NULL DEFAULT 0,
    i_money INTEGER NOT NULL DEFAULT 0,
    by_direct_attack SMALLINT NOT NULL DEFAULT 0,
    by_magic_attack SMALLINT NOT NULL DEFAULT 0,
    area_range REAL NOT NULL DEFAULT 0,
    PRIMARY KEY (s_sid, is_monster)
);

